import{_ as a,c as i,a as e,o as n}from"./app-CEcM0piI.js";const l={};function d(t,s){return n(),i("div",null,s[0]||(s[0]=[e(`<p>java是一个编译解释混合型语言，写好的java程序需要先编译成字节码，然后在虚拟机上运行将字节码翻译成二进制指令</p><p>java编译一次到处运行，具有安全性 python是把源代码逐句翻译成二进制指令，因此要运行python程序即运行python程序的源代码没有安全性</p><h1 id="文档注释" tabindex="-1"><a class="header-anchor" href="#文档注释"><span>文档注释</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>/**</span></span>
<span class="line"><span>@version:</span></span>
<span class="line"><span>@属性名: 如作用，参数，返回值，版本，作者等</span></span>
<span class="line"><span>*/</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>可以被jdk提供的工具javadoc所解析，生成一套以网页形式体现的该程序的说明文档</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//编译</span></span>
<span class="line"><span>javac 文件名(.java文件)</span></span>
<span class="line"><span>//运行</span></span>
<span class="line"><span>java 文件名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>空类型是null</p><h1 id="数据类型" tabindex="-1"><a class="header-anchor" href="#数据类型"><span>数据类型</span></a></h1><h2 id="基本数据类型" tabindex="-1"><a class="header-anchor" href="#基本数据类型"><span>基本数据类型</span></a></h2><p>byte数字类型范围是-127 128<br> byte short char在进行运算的时候会先提升为int再进行运算<br> 布尔类型是boolean<br> long类型是直接写long不需要加int，且long类型的数字字面量必须是以l作后缀无所谓大小写<br> float必须以f作后缀而double不需要<br> 字符串类型只有+运算（拼接）</p><h2 id="引用数据类型" tabindex="-1"><a class="header-anchor" href="#引用数据类型"><span>引用数据类型</span></a></h2><p>Scanner类型用于获取键盘输入<br> 导包<br> import java.until.Scanner<br> 创建对象（使用这个类）<br> Scanner sc=new Scanner(System.in);<br> 接收数据<br> int i=sc.nextInt</p><h1 id="数组" tabindex="-1"><a class="header-anchor" href="#数组"><span>数组</span></a></h1><p>定义 两种定义方式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int[] array;</span></span>
<span class="line"><span>int array[];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>动态初始化：手动指定数组长度，由系统给出默认初始值</li><li>静态初始化：手动指定数组元素，系统会根据元素个数计算出数组的长度</li></ul><p>静态初始化</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int[] array=new int[]{1,2,3};</span></span>
<span class="line"><span>int[] array={1,2,3};</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>直接打印数组打印出来的是数组的地址，如：[I@776ec8df 其中I表示int整形的意思，D就是表示double型 @是固定格式的间隔符号 后面的十六进制数才是地址</p><p>获取数组的长度</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>array.length;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>动态初始化</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>数据类型[] 数组名= new 数据类型[数组的长度]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>程序员给出数组的长度，由虚拟机给出是默认的初始化值</p><table><thead><tr><th>数据类型</th><th>默认初始化值</th></tr></thead><tbody><tr><td>整型</td><td>0</td></tr><tr><td>小数</td><td>0.0</td></tr><tr><td>字符</td><td>&#39;/u0000&#39;空格</td></tr><tr><td>布尔</td><td>false</td></tr><tr><td>引用</td><td>null</td></tr></tbody></table><h1 id="方法的重载" tabindex="-1"><a class="header-anchor" href="#方法的重载"><span>方法的重载</span></a></h1><p>java中的方法就是c或Python中的函数 在同一个类中允许定义多个同名函数其参数类型和参数个数不同即构成重载。与返回值无关</p><h2 id="引用数据类型-1" tabindex="-1"><a class="header-anchor" href="#引用数据类型-1"><span>引用数据类型</span></a></h2><p>使用new出来的数据类型都是引用数据类型 数组就是引用数据类型，数组定义的完整形式是使用new运算符了 引用数据类型的变量存储的都是地址值</p><p>引用：使用了其他空间中的数据 基本数据类型数据值是存储在自己的空间中赋值给其他变量是拷贝值过去修改值不影响原变量 引用数据类型数据值存储在其他空间，自己空间存储的是地址值，赋值给其他变量时拷贝的是地址的值这样两变量指向的是同一个数据修改也会影响另一个</p><p>String字符串也是引用数据类型</p><h1 id="类和对象" tabindex="-1"><a class="header-anchor" href="#类和对象"><span>类和对象</span></a></h1><h1 id="lambda" tabindex="-1"><a class="header-anchor" href="#lambda"><span>lambda</span></a></h1><ul><li>() 对应着方法的形参列表</li><li>-&gt;固定格式</li><li>{} 方法的方法体</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>()-&gt;{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>lambda表达式可以用来简化匿名内部类的书写 lambda表达式只能简化函数式接口的匿名内部类写法</p><p>函数式接口: 有且仅有一个抽象方法的接口叫做函数式接口(可以使用@Functionallnterface注解判断是否是函数式接口,如果报错则不是)</p><p>lambda的省略规则：</p><ol><li>参数类型可以省略不写。</li><li>如果只有一个参数，参数类型可以省略，同时（)也可以省略。</li><li>如果Lambda表达式的方法体只有一行，大括号，分号，return可以省略不写，需要同时省略。 如:</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Integer[] arr = {1,2,3,4,5};</span></span>
<span class="line"><span>Arrays.sort(arr,new Comparetor&lt;Integer&gt;(){</span></span>
<span class="line"><span>    @Override</span></span>
<span class="line"><span>    public int compare(Integer o1,Integer o2){</span></span>
<span class="line"><span>        return o1-o2;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}); </span></span>
<span class="line"><span></span></span>
<span class="line"><span>//lambda完整格式</span></span>
<span class="line"><span>Arrays.sort(arr,(Integer o1,Integer o2)-&gt;{</span></span>
<span class="line"><span>    return o1-o2;</span></span>
<span class="line"><span>});</span></span>
<span class="line"><span>//lambda省略写法</span></span>
<span class="line"><span>Arrays.sort(arr,(o1, o2)-&gt; o1 -o2);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="泛型" tabindex="-1"><a class="header-anchor" href="#泛型"><span>泛型</span></a></h1><p>泛型尖括号中只能写引用数据类型 对于一个集合如果不使用泛型指定其中内容的类型则该集合可以存储任意的类型 但存储的类型都会转化为Object对象来存储,因此无法调用子类特有的方法但可以强制类型转换后使用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ArrayList list=new ArrayList();</span></span>
<span class="line"><span>list.add(123);</span></span>
<span class="line"><span>list.add(&quot;aaa&quot;);</span></span>
<span class="line"><span>list.add(new Student( name:&quot;zhangsan&quot;, age: 123));</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但java中的泛型是伪泛型,当数据存储到集合中时会将对象转换为object类型,但是当取出时又会自动强转为指定的数据类型</p><h2 id="泛型类" tabindex="-1"><a class="header-anchor" href="#泛型类"><span>泛型类</span></a></h2><p>当自己写一个泛型类的时候可以在尖括号中填写任一字母指代类型 自己实现一个ArrayList:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class MyArrayList&lt;E&gt; {</span></span>
<span class="line"><span>	Object[] obj= new object[10];</span></span>
<span class="line"><span>	int size;</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	public E get(int index){</span></span>
<span class="line"><span>		return (E)obj[index];</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="泛型方法" tabindex="-1"><a class="header-anchor" href="#泛型方法"><span>泛型方法</span></a></h2><h3 id="类名后面定义的泛型" tabindex="-1"><a class="header-anchor" href="#类名后面定义的泛型"><span>类名后面定义的泛型</span></a></h3><p>所有方法都能用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>修饰符&lt;类型&gt;返回值类型 方法名(类型 变量名){}</span></span>
<span class="line"><span>public&lt;T&gt;void show(T t){}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="在方法申明上定义自己的泛型" tabindex="-1"><a class="header-anchor" href="#在方法申明上定义自己的泛型"><span>在方法申明上定义自己的泛型</span></a></h3><p>只有本方法能用</p><h2 id="泛型接口" tabindex="-1"><a class="header-anchor" href="#泛型接口"><span>泛型接口</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>修饰符 interface 接口名&lt;类型&gt;{}</span></span>
<span class="line"><span>public interface List&lt;E&gt;{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>实现类给出类型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class MyArrayList implements List&lt;String&gt;{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>实现类延续泛型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class MyArrayList&lt;E&gt; implements List&lt;E&gt;{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="泛型的通配符" tabindex="-1"><a class="header-anchor" href="#泛型的通配符"><span>泛型的通配符</span></a></h2><p>泛型不具备继承性,但数据具备继承性 如:B继承A 在method的方法中已经指定了比如传入A类型的ArrayList,但它的孩子不能传递</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public static void method(ArrayList&lt;A&gt; list){}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ArrayList&lt;A&gt; la=new ArrayList&lt;&gt;;</span></span>
<span class="line"><span>ArrayList&lt;B&gt; lb=new ArrayList&lt;&gt;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>method(la);//ok</span></span>
<span class="line"><span>method(lb);//error</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果想要一个类型或方法能够接收一个类型及与其有继承关系的类型可以使用通配符</p><ul><li>？也表示不确定的类型他可以进行类型的限定</li><li>? extends E：表示可以传递E或者E所有的子类类型</li><li>? super E：表示可以传递E或者E所有的父类类型</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public static void method(ArrayList&lt;? extends A&gt;list）{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>method可以接收E类型及其子类</p>`,66)]))}const p=a(l,[["render",d]]),h=JSON.parse('{"path":"/back/java/1/","title":"1 Java","lang":"zh-CN","frontmatter":{"title":"1 Java","createTime":"2025/06/22 09:46:34","permalink":"/back/java/1/"},"readingTime":{"minutes":5.27,"words":1580},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Java/1 Java.md","headers":[]}');export{p as comp,h as data};
